    name                              = "examplecdnfdwafpolicy1"
    resource_group_name               = azurerm_resource_group.this.name
    sku_name                          = "Premium_AzureFrontDoor" # Ensure SKU_name for WAF is similar to SKU_name for front door profile.
    enabled                           = true
    mode                              = "Prevention"
    redirect_url                      = "https://www.contoso.com"
    custom_block_response_status_code = 405
    custom_block_response_body        = "PGh0bWw+CjxoZWFkZXI+PHRpdGxlPkhlbGxvPC90aXRsZT48L2hlYWRlcj4KPGJvZHk+CkhlbGxvIHdvcmxkCjwvYm9keT4KPC9odG1sPg=="

    custom_rules = {
      cr1 = {
        name                           = "Rule1"
        enabled                        = true
        priority                       = 1
        rate_limit_duration_in_minutes = 1
        rate_limit_threshold           = 10
        type                           = "MatchRule"
        action                         = "Block"
        match_conditions = {
          m1 = {
            match_variable     = "RemoteAddr"
            operator           = "IPMatch"
            negation_condition = false
            match_values       = ["10.0.1.0/24", "10.0.0.0/24"]
          }
        }
      }

      cr2 = {
        name                           = "Rule2"
        enabled                        = true
        priority                       = 2
        rate_limit_duration_in_minutes = 1
        rate_limit_threshold           = 10
        type                           = "MatchRule"
        action                         = "Block"
        match_conditions = {
          match_condition1 = {
            match_variable     = "RemoteAddr"
            operator           = "IPMatch"
            negation_condition = false
            match_values       = ["192.168.1.0/24"]
          }

          match_condition2 = {
            match_variable     = "RequestHeader"
            selector           = "UserAgent"
            operator           = "Contains"
            negation_condition = false
            match_values       = ["windows"]
            transforms         = ["Lowercase", "Trim"]
          }
        }
      }
    }
    managed_rules = {
      mr1 = {
        type    = "Microsoft_DefaultRuleSet"
        version = "2.1"
        action  = "Log"
        exclusions = {
          exclusion1 = {
            match_variable = "QueryStringArgNames"
            operator       = "Equals"
            selector       = "not_suspicious"
          }
        }
        overrides = {
          override1 = {
            rule_group_name = "PHP"
            rule = {
              rule1 = {
                rule_id = "933100"
                enabled = false
                action  = "Log"
              }
            }
          }
          override2 = {
            rule_group_name = "SQLI"
            exclusions = {
              exclusion1 = {
                match_variable = "QueryStringArgNames"
                operator       = "Equals"
                selector       = "really_not_suspicious"
              }
            }
            rules = {
              rule1 = {
                rule_id = "942200"
                action  = "Log"
                exclusions = {
                  exclusion1 = {
                    match_variable = "QueryStringArgNames"
                    operator       = "Equals"
                    selector       = "innocent"
                  }
                }
              }
            }
          }
        }
      }

      mr2 = {
        type    = "Microsoft_BotManagerRuleSet"
        version = "1.0"
        action  = "Log"
      }
    }
  }
}
